        { id: 3, name: 'Admin', email: 'admin@example.com', role: 'admin' },
      ];

      // Apply pagination
      const paginatedUsers = allUsers.slice(offset, offset + limit);

      // Filter sensitive data
      const filteredUsers = paginatedUsers.map(user =>
        filterUserData(user, req.user)
      );

      res.status(200).json({
        data: filteredUsers,
        pagination: {
          limit,
          offset,
          total: allUsers.length,
          hasMore: offset + limit < allUsers.length,
        },
      });
    } catch (error) {
      next(error);
    }
  }
