    // Validate required fields
    if (!email || !password) {
      return res.status(400).json({
        error: {
          message: 'Email and password required',
          code: 'MISSING_CREDENTIALS',
        },
      });
    }

    // Validate email format
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
      return res.status(400).json({
        error: {
          message: 'Invalid email format',
          code: 'INVALID_EMAIL',
        },
      });
    }

    // Mock user verification (in production, use bcrypt for password comparison)
    const mockUsers = [
      { id: 1, email: 'alice@example.com', name: 'Alice', role: 'user' },
      { id: 2, email: 'admin@example.com', name: 'Admin', role: 'admin' },
    ];

    const user = mockUsers.find(u => u.email === email);

    if (!user || password !== 'demo-password') {
      logger.warn(`Failed login attempt for email: ${email}`);
      return res.status(401).json({
        error: {
          message: 'Invalid credentials',
          code: 'INVALID_CREDENTIALS',
        },
      });
    }

    // Generate JWT token
    const token = jwt.sign(
      {
        id: user.id,
        email: user.email,
        role: user.role,
      },
      config.jwtSecret,
      { expiresIn: '1h' }
    );

