```javascript
// Enhanced application with security best practices
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const validator = require('validator');

const app = express();

// Security Middleware
app.use(helmet()); // Add security headers
app.use(express.json({ limit: '10kb' })); // Limit payload size

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests, please try again later.'
});
app.use(limiter);

// Input validation middleware
const validateQuery = (req, res, next) => {
  const allowedParams = ['id', 'name', 'email'];
  const invalidParams = Object.keys(req.query).filter(
    param => !allowedParams.includes(param)
  );

  if (invalidParams.length > 0) {
    return res.status(400).json({
      error: 'Invalid query parameters',
      invalid: invalidParams
    });
  }

  // Sanitize inputs
  Object.keys(req.query).forEach(key => {
    req.query[key] = validator.trim(String(req.query[key]));
  });

  next();
};

// Health check endpoint
app.get('/health', (req, res) => {
  try {
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString() 
    });
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Users endpoint with validation and error handling
app.get('/users', validateQuery, (req, res) => {
  try {
    const mockUsers = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Filter by ID if provided and validate
    if (req.query.id) {
      const id = parseInt(req.query.id, 10);
      if (isNaN(id) || id < 0) {
        return res.status(400).json({ error: 'Invalid ID format' });
      }
      const filtered = mockUsers.filter(u => u.id === id);
      return res.json(filtered);
    }

    res.json(mockUsers);
  } catch (error) {
    console.error('Error fetching users:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Global error handler
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);

  // Don't expose internal error details in production
  const message = process.env.NODE_ENV === 'production' 
    ? 'Internal server error' 
    : err.message;

  res.status(err.status || 500).json({ 
    error: message,
    ...(process.env.NODE_ENV !== 'production' && { stack: err.stack })
  });
});

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Endpoint not found' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

